room_table = {
{room=1,  	title="Lost in Darkness", 	verbose="Although you did but recently return from your epic adventuring in the Land of Xesse you have already grown weary of the fame and adulation that greeted your homecoming. Once more your craving for excitement has forced you to search out an entrance to another plane of the multiverse where magic works and logic can be really rather unreliable....\nA sign flashes in the darkness suggesting that you \"Go West\".", 	n=2, 	s=2, 	e=580, 	w=2, 	ne=2, 	nw=2, 	se=2, 	sw=2, 	i=2, 	o=2, 	u=2, 	d=2},
{room=2,  	title="Entrance Tunnel", 	verbose="You have arrived in a dark and gloomy tunnel hewn from solid rock. The walls are damp to the touch and you can hear the rustle of bats wings in the darkness above you. The tunnel runs east and west from here but unfortunately passage east is impossible as the roof of the tunnel has caved in creating an impassable barrier. Light can be seen filtering in from the west so that\'s probably not a bad direction to move in.", 	n="Walking through walls was never your strong point", 	s="You can\'t go that way.", 	e="Walking through walls was never your strong point", 	w=3, 	ne="You can\'t go that way.", 	nw="Walking through walls was never your strong point", 	se="You can\'t go that way.", 	sw="Walking through walls was never your strong point", 	i="Walking through walls was never your strong point", 	o=3, 	u="You must be bats!", 	d="You can\'t go that way."},
{room=3,  	title="Tunnel mouth", 	verbose="This is the mouth of a damp tunnel where it merges into a large cavern. You can hear the dripping of water around you and you can smell the fetid odour of many bats issuing from the tunnel which lies to the east of you. An enormous profusion of stalactites and stalagmites grow here making progress difficult although they do seem to thin out somewhat to the northwest.", 	n="Walking through walls was never your strong point", 	s="You can\'t go that way.", 	e=2, 	w=4, 	ne="Walking through walls was never your strong point", 	nw=4, 	se="You can\'t go that way.", 	sw="Walking through walls was never your strong point", 	i=2, 	o=4, 	u="You must be bats!", 	d="You can\'t go that way."},
{room=4,  	title="Natural Cavern", 	verbose="You are now standing in the approximate center of a large natural cavern which is filled with stalactites and stalagmites. The scene is visible by the light of luminous rocks which appear to have been embedded in the walls high above your head. Many trails twist and turn across the cavern with a larger one leading north from which direction you can feel a fresh breeze. The walls themselves appear covered in graffiti.\nA sign reading \"Information\" hangs from the roof, pointing east.", 	n=5, 	s=22, 	e=841, 	w="You can\'t go that way.", 	ne="Walking through walls was never your strong point", 	nw=5, 	se=3, 	sw="You can\'t go that way.", 	i=841, 	o=5, 	u="You must be bats!", 	d="You can\'t go that way."},
{room=5,  	title="Cavern entrance", 	verbose="A path which runs roughly north-south emerges from the side of a steep hill here. Looking south you can see that the path leads into a cavern of some sort and looking north you can see that the path twists and winds into a forest before becoming lost to sight, to the northwest is a wide, deep moat.\nHanging from the cavern ceiling there is a lone stalactite Upon closer inspection you see an inscription carved into it that reads \'In memory of Icecold - RIP David\'", 	n=11, 	s=4, 	e="Walking through walls was never your strong point", 	w=6, 	ne="You can\'t go that way.", 	nw=6, 	se=4, 	sw=55, 	i=4, 	o=6, 	u="You must be bats!", 	d="You can\'t go that way."},
