{room=133,  	title="South bank of river", 	verbose="The trees thin out here and you find yourself on the south bank of a river which flows to the west from here. Across the river to the northeast you can see a stone jetty but everywhere else is forest.", 	n="You would only fall in and drown.", 	s=136, 	e="You can\'t go that way.", 	w=132, 	ne="You really should have learnt to swim.", 	nw="You really should have learnt to swim.", 	se=137, 	sw=136, 	i=136, 	o=132, 	u="Think you\'re a squirrel?", 	d="You can\'t go that way."},
{room=134,  	title="South bank of river", 	verbose="You are on the south bank of a fast flowing river across which you can see an old stone jetty. All around you to the west and south is forest although many of the trees have been cut down. To the east is a tall cliff and nestled at its base is a small hut. Upstream to the northeast you can see the source of the river which is a waterfall thundering down the cliff face.", 	n="You would only fall in and drown.", 	s=137, 	e=135, 	w=133, 	ne="You really should have learnt to swim.", 	nw="You would only fall in and drown.", 	se=138, 	sw=136, 	i=135, 	o=133, 	u="Think you\'re a bird?", 	d="You can\'t go that way."},
{room=135,  	title="Lumberjack\'s tool shed", 	verbose="This is the interior of a small hut which seems to be where a lumberjack used to keep his tools. Now it\'s just a dusty hut filled with many years accumulation of cobwebs.", 	n="Walking through walls was never your strong point", 	s="Walking through walls was never your strong point", 	e="You walk into something solid.", 	w=134, 	ne="You can\'t go that way.", 	nw="Walking through walls was never your strong point", 	se="You walk into something solid.", 	sw="You can\'t go that way.", 	i="You can\'t go that way.", 	o=134, 	u="You must be bats!", 	d="You can\'t go that way."},
{room=136,  	title="Forest by road", 	verbose="The forst thins out to the south where there is an old but still serviceable road. To the west the forst becomes very dense while to the east you can see a clearing.", 	n=132, 	s=141, 	e=137, 	w=143, 	ne=133, 	nw=132, 	se=141, 	sw=140, 	i=141, 	o=132, 	u="Think you\'re a bird?", 	d="You can\'t go that way."},
{room=137,  	title="Clearing in forest", 	verbose="You are standing in the approximate centre of a clearing which seems to be man made judging by the number of rotting tree stumps which protrude from the ground. Northeast a small hut huddles under an cliff face while to the south there is an old but usable road.", 	n=134, 	s=140, 	e=138, 	w=136, 	ne=135, 	nw=133, 	se=139, 	sw=141, 	i=141, 	o=133, 	u="You can\'t go that way.", 	d="You can\'t go that way."},
{room=138,  	title="Forest at base of cliff", 	verbose="The forest stops at the base of a cliff to the east here although a road to the south appears easy to reach. Apart from that its difficult to see anything but there may be a clearing to the west.", 	n="The forest is too dense.", 	s=139, 	e="You walk into something solid.", 	w=137, 	ne="The forest is too dense.", 	nw=134, 	se="The forest is too dense.", 	sw=140, 	i=140, 	o=137, 	u="You must be bats!", 	d="You can\'t go that way."},
{room=139,  	title="Road past ruined city", 	verbose="You are on an east/west road which leads into the cliff face here. It seems as if some sort of structure have been built inside the cliff which you can enter to the east. Apart from this you can walk west along the road or strike north into the forest.", 	n=138, 	s="You walk into something solid.", 	e=241, 	w=140, 	ne="You can\'t go that way.", 	nw=137, 	se="You can\'t go that way.", 	sw="You can\'t go that way.", 	i=140, 	o=137, 	u="Think you\'re a bird?", 	d="You can\'t go that way."},
{room=140,  	title="Road by clearing", 	verbose="The road runs east and west for here and is bounded on the south side by a tall stone wall. There does however seem to be a way through the wall along to the southwest.", 	n=137, 	s="You walk into something solid.", 	e=139, 	w=141, 	ne=138, 	nw=136, 	se="You can\'t go that way.", 	sw=141, 	i=141, 	o=136, 	u="Think you\'re a bird?", 	d="You can\'t go that way."},
{room=141,  	title="Road opposite entrance", 	verbose="You are standing at the end of a road which runs off to the east from here. Both north and west of you there is dense forest while to the south is an entrance through a high stone wall.", 	n=136, 	s=142, 	e=140, 	w=143, 	ne=137, 	nw=143, 	se=142, 	sw=142, 	i=142, 	o=136, 	u="Think you\'re a bird?", 	d="You can\'t go that way."},
{room=142,  	title="Entrance to Ruined city", 	verbose="This is the entrance to the ruined city which is bounded to the north by a high stone wall. You are standing in the only entrance through this wall and looking south you have a view of a ruined, desolate city although it was once both rich and beautiful. There is a pair of splendid brass gates across the entrance, obviously intended to keep undesirables out of the city.", 	n=141, 	s=150, 	e="You can\'t go that way.", 	w="You can\'t go that way.", 	ne=141, 	nw=141, 	se="You can\'t go that way.", 	sw="You can\'t go that way.", 	i=150, 	o=136, 	u="You must be bats!", 	d="You can\'t go that way."},
