{room=182,  	title="Jeweller\'s viewing room", 	verbose="This is the room where the nobles would come to view the finest jewellery the city could provide and to occasionally buy a rare and priceless item to add to their collections. To the north some dusty and ragged curtains cunningly conceal the archway to the shop.", 	n=181, 	s="You walk into something solid.", 	e=183, 	w="You can\'t go that way.", 	ne="You walk into something solid.", 	nw="You can\'t go that way.", 	se="Walking through walls was never your strong point", 	sw="You can\'t go that way.", 	i="Walking through walls was never your strong point", 	o=181, 	u="You can\'t go that way.", 	d="You can\'t go that way."},
