{room=233,  	title="Trapdoor in passageway to West Tower", 	verbose="As you climb the steps you find that your head encounters the underneath of a trapdoor which lifts, giving you a worms eye view of the corridor to the West tower. You realise that if you should climb right out into the passageway you probably wouldn\'t be able to re-open the trapdoor from that side.", 	n="You can\'t go that way.", 	s="You can\'t go that way.", 	e=74, 	w="You can\'t go that way.", 	ne="You can\'t go that way.", 	nw="You can\'t go that way.", 	se="You can\'t go that way.", 	sw="You can\'t go that way.", 	i="You can\'t go that way.", 	o=74, 	u=74, 	d=232},
