{room=236,  	title="Immortality Cubicle.", 	verbose="The centre of the room contains a small plinth with some sort of keyboard set in its top. The keys are inscribed with runes which bear a resemblance to the English alphabet. Inscribed in an archaic script on the front of the plinth are the words \'Immortality Transmogrifier - Enter code\'.\nLooking up you notice a fine skein of electric blue crawling across the undersurface of the ceiling.", 	n=240, 	s=235, 	e=240, 	w=240, 	ne=240, 	nw=240, 	se=240, 	sw=240, 	i=240, 	o=235, 	u=240, 	d=240},
