{room=257,  	title="The magic room", 	verbose="You can barely stand the terrifying power abundant in this small cave. In the exact centre of the room is what appears to be a well. From the well bursts forth a beam of what can only be described as raw magic, perhaps the actual source of all magic in the Land. Shielding your eyes from the glare you are able to detect a tiny exit to the northwest.", 	n="There appears to be a wall in the way.", 	s="There appears to be a wall in the way.", 	e="There appears to be a wall in the way.", 	w="There appears to be a wall in the way.", 	ne="There appears to be a wall in the way.", 	nw=258, 	se="There appears to be a wall in the way.", 	sw="There appears to be a wall in the way.", 	i=258, 	o=255, 	u=255, 	d="You are standing on solid rock. Very solid."},
{room=258,  	title="Tiny niche", 	verbose="This is a tiny niche cutting into the northwestern wall of the magic room, and is completely bathed in the magical glow from the well. You can re-enter the magic room by going southeast.", 	n="The rock isn\'t quite thin enough to be walked through.", 	s="There appears to be a wall in the way.", 	e="The rock isn\'t quite thin enough to be walked through.", 	w="There appears to be a wall in the way.", 	ne="The rock isn\'t quite thin enough to be walked through.", 	nw="There appears to be a wall in the way.", 	se=257, 	sw="The rock isn\'t quite thin enough to be walked through.", 	i="There appears to be a wall in the way.", 	o=257, 	u="Sorry. No levitating on these premises.", 	d="You are standing on solid rock. Very solid."},
