{room=275,  	title="At the end of a tunnel.", 	verbose="You are at the end of a long tunnel leading west. To the south there is a large white room and on one wall an arrow points to the room below a sign which says \"Beware...do not go any further\", and to the east there is a small room.", 	n="You blunder into a cold, hard wall.", 	s=276, 	e=721, 	w=274, 	ne="Walking through walls was never your strong point", 	nw="You blunder into a cold, hard wall.", 	se="Walking through walls was never your strong point", 	sw="You blunder into a cold, hard wall.", 	i=276, 	o=274, 	u="You must be bats!", 	d="You can\'t go that way."},
{room=276,  	title="In a large white room.", 	verbose="You are in a large white cavern. The walls and ceiling appear to be made of solid marble and there is a white carpet on the floor. The room is lit by glowing spheres hanging from the ceiling far above your head and there is a long rope stretching down from the middle of the ceiling to about shoulder height.\nA sign on the rope says \'Pull Me\'", 	n=275, 	s=277, 	e="You blunder into a cold, hard wall.", 	w="Walking through walls was never your strong point", 	ne="Walking through walls was never your strong point", 	nw="You blunder into a cold, hard wall.", 	se="You blunder into a cold, hard wall.", 	sw="Walking through walls was never your strong point", 	i=277, 	o=275, 	u="You must be bats!", 	d="You can\'t go that way."},
{room=277,  	title="Small passageway.", 	verbose="This is a small, well lit passageway, leading south. There is a comfortable, black carpet on the floor and the ceiling is painted a strangely unsettling shade of pink. A sign on one wall says \'Ambushbug\'s Secret Hideout this way\' and an arrow points to the north.", 	n=276, 	s=279, 	e="Walking through walls was never your strong point", 	w="You blunder into a cold, hard wall.", 	ne="You blunder into a cold, hard wall.", 	nw="You blunder into a cold, hard wall.", 	se="Walking through walls was never your strong point", 	sw="Walking through walls was never your strong point", 	i=279, 	o=276, 	u="You must be bats!", 	d="You can\'t go that way."},
{room=278,  	title="A dark, gloomy passageway.", 	verbose="This is a dark gloomy passageway with high concrete walls on either side. To the north there is a door marked \'LADIES\', which has been painted a dark brown to make the passageway seem a little more cheery.", 	n=270, 	s=163, 	e="Walking through walls was never your strong point", 	w="Walking through walls was never your strong point", 	ne="Walking through walls was never your strong point", 	nw="Walking through walls was never your strong point", 	se="Walking through walls was never your strong point", 	sw="You blunder into a cold, hard wall.", 	i=270, 	o=163, 	u="You can\'t go that way.", 	d="You can\'t go that way."},
{room=279,  	title="Ambushbug\'s Secret Hideout", 	verbose="This is a large expansive room filled with many luxuries and treasures. In one corner there is a large four poster bed complete with continental quilt and teddy bear, and most walls hold tapestries depicting strange scenes and showing the fates of many hapless mortals. An old, time-worn oaken desk holds many scrolls and books, piled haphazardly. If you listen quietly you might just hear a faint chuckling and something that sounds vaguely like a lunatic shouting \'Whoop! Whoop! Whoop!\'.", 	n=277, 	s=279, 	e=280, 	w=280, 	ne="You blunder into a cold, hard wall.", 	nw="You blunder into a cold, hard wall.", 	se="You blunder into a cold, hard wall.", 	sw="Walking through walls was never your strong point", 	i=279, 	o=277, 	u=187, 	d=280},
{room=280,  	title="Wet, slippery tunnel", 	verbose="You are in a dark, slippery tunnel sloping downwards to the east.  The walls are thickly encrusted, water runs down the tunnel and the floor is so slippery that you keep slipping downwards. From below you can hear a loud regular splashing sound as though the water is falling a great distance into a large, deep lake.", 	n="You can\'t go that way.", 	s="You can\'t go that way.", 	e=375, 	w="You can\'t go that way.", 	ne="You can\'t go that way.", 	nw="You can\'t go that way.", 	se="You can\'t go that way.", 	sw="You can\'t go that way.", 	i=375, 	o=375, 	u="You can\'t go that way.", 	d=375},
{room=281,  	title="Immortals Index Area", 	verbose="These rooms are definitely a touch of class - you feel proud and privileged to be one of the few to gain access to them. Doors lead off in several directions, and on each door is a sign....\nThe North Door is marked \"Immortals Commands\"\nThe East Door is marked \"Immortal behaviour\"\nThe West Door is marked \"Immortals News\"\nThe South Door is marked \"Room numbers\"", 	n=282, 	s=294, 	e=295, 	w=855, 	ne="You can\'t go that way.", 	nw="You can\'t go that way.", 	se="You can\'t go that way.", 	sw="You can\'t go that way.", 	i=855, 	o="You can\'t go that way.", 	u="You can\'t go that way.", 	d="You can\'t go that way."},
