{room=406,  	title="Northeast of Arena", 	verbose="Panting heavily you arrive at the northest of the arena. The walls here have been damaged by the lions as they climb out of the arena.", 	n="You walk straight into a wall. Ouch.", 	s=405, 	e="You squash your nose against the wall.", 	w=403, 	ne="Walking through walls was never your strong point", 	nw="Walking through walls was never your strong point", 	se="You squash your nose against the wall.", 	sw=402, 	i=402, 	o=403, 	u=407, 	d="You scratch madly at the floor but achieve nothing."},
{room=407,  	title="Top of Wall", 	verbose="Sitting on top of the wall you are able to take stock of the situation more calmly, but you still have to survive your trip back into the city. Calculating risks and options you wonder whether to leave the wall to the northeast, or whether to jump back down into the arena.", 	n="That direction isn\'t too safe.", 	s="Going that way could hurt....", 	e="That direction isn\'t too safe.", 	w="Going that way could hurt....", 	ne=408, 	nw="Going that way could hurt....", 	se="That direction isn\'t too safe.", 	sw="Going that way could hurt....", 	i=406, 	o=408, 	u="You flap your arms furiously and rise about a hairs breadth.", 	d=406},
