{room=476,  	title="Under the Black tower", 	verbose="A passageway from the north opens up into a room which has been smoothly carved from the rock, revealing coloured patterns of an almost ethereal quality within the walls. Archways lead into two small chambers to the east and the west.  The patterns appear distorted and chaotic around the entrance to the west chamber, and are rather disturbing to the eye.", 	n=475, 	s="You can\'t go that way.", 	e=477, 	w=478, 	ne="You can\'t go that way.", 	nw="You can\'t go that way.", 	se="You can\'t go that way.", 	sw="You can\'t go that way.", 	i="You can\'t go that way.", 	o=475, 	u="You can\'t go that way.", 	d="You can\'t go that way."},
{room=477,  	title="East Chamber", 	verbose="You are in a small chamber whose walls are coloured in soft, relaxing shades of pastel colours. Along one wall the rock forms a sort of bench or couch, which is pleasantly warm to the touch.  Looking through the only exit to the room (to your west) you can see across one room to another chamber, similiar to this one.", 	n="You can\'t go that way.", 	s="You can\'t go that way.", 	e="You can\'t go that way.", 	w=476, 	ne="You can\'t go that way.", 	nw="You can\'t go that way.", 	se="You can\'t go that way.", 	sw="You can\'t go that way.", 	i="You can\'t go that way.", 	o=476, 	u="You can\'t go that way.", 	d="You can\'t go that way."},
