{room=485,  	title="Perilous Bridge", 	verbose="The Perilous Bridge spans the Chasm, its loose and broken boards creek as they are battered by the wind. Below you through the gaps you see the vicious rocks in the Chasm below. One look tells you it\'s time to move on. To the south the road leads to the Main Gate of the Mayors Mansion, the only other healthy exit is to the North.", 	n=173, 	s=486, 	e="Going that way could hurt....", 	w="Going that way could hurt....", 	ne="Going that way could hurt....", 	nw="Going that way could hurt....", 	se="Going that way could hurt....", 	sw="Going that way could hurt....", 	i="You can\'t go that way.", 	o=173, 	u="Think you\'re a bird?", 	d="Going that way could hurt...."},
{room=486,  	title="Main Gate to the Mansion.", 	verbose="The gates to the Mayoral Mansion reflect the glory that was. The Massive wrought iron gates are closed, and the huge lock makes one wonder whether such a large key could be carried around. High on the wall beside the gate is a small hole, too high for you to reach.  Beside the gates, firmly affixed to the wall is a sign that reads \'No Hawkers, Traders, or Adventurers.\' The road leads off to both southeast and north from here.", 	n=485, 	s="The gate is firmly closed.", 	e="The rubble is impenetrable.", 	w="The rubble is impenetrable.", 	ne="Going that way could hurt....", 	nw="Going that way could hurt....", 	se=487, 	sw="You blunder into a cold, hard wall.", 	i="You can\'t go that way.", 	o=485, 	u="You can\'t climb up here.", 	d="You can\'t go that way."},
{room=487,  	title="Wall, North East Corner of Mansion.", 	verbose="To the West there is a high granite wall. The path leads only to the SouthWest and the NorthWest from here.", 	n="The rubble is impenetrable.", 	s="The rubble is impenetrable.", 	e="A mysterious force prevents you moving that way", 	w="You blunder into a cold, hard wall.", 	ne="A mysterious force prevents you moving that way", 	nw=486, 	se="You can\'t go that way.", 	sw=490, 	i="You can\'t go that way.", 	o=486, 	u="Think you\'re a bird?", 	d="You can\'t go that way."},
{room=488,  	title="South of Main Gate.", 	verbose="The wrought iron gates of the Mansion are to the north, with a small hole in the wall beside them. The other paths are to the west and to the southwest.", 	n=486, 	s="You blunder into a cold, hard wall.", 	e="You walk into something solid.", 	w=489, 	ne="There\'s no entrance there!", 	nw="Going that way could hurt....", 	se="Walking through walls was never your strong point", 	sw=491, 	i="You can\'t go that way.", 	o="A mysterious force prevents you moving that way", 	u="Think you\'re a squirrel?", 	d="You can\'t go that way."},
