{room=721,  	title="An underground room.", 	verbose="You are in a small, dingy underground room. The walls are covered with a fairly weedy looking growth of moss and from the ceiling small stalactites are starting to grow. In the east wall there is a small archway with a sign tacked to the wall next to it. The sign reads:\n\"Ambushbug\'s Chaos Emporium - Authorised Personnel Only\".", 	n="Walking through walls was never your strong point", 	s="There\'s no entrance there!", 	e=722, 	w=275, 	ne="You blunder into a cold, hard wall.", 	nw="You can\'t go that way.", 	se="You can\'t go that way.", 	sw="You can\'t go that way.", 	i=722, 	o=275, 	u="You can\'t go that way.", 	d="You can\'t go that way."},
{room=722,  	title="Entrance to Ambushbug\'s Chaos Emporium.", 	verbose="This is a large lavish room with many expensive marble and gold fittings, all securely bolted down. There are two sliding metal doors on the east wall below a sign saying \"Elevator to surface\". Another sign bears the legend \"Out of order\" and hangs just below the first one.  Exits lead north, south, and west.", 	n=723, 	s=732, 	e="The elevator doors are jammed shut.", 	w=721, 	ne="You can\'t go that way.", 	nw="You can\'t go that way.", 	se="You can\'t go that way.", 	sw="You can\'t go that way.", 	i=732, 	o=721, 	u="You can\'t go that way.", 	d="You can\'t go that way."},
{room=723,  	title="Outside the Haunted House.", 	verbose="Before you is an eerie looking building, extremely gothic with turrets and fancy windows and strange looking gargoyles perched on the walls.  In the south side of the building there is a tall wooden door with a fancy doorknocker in the shape of a demon of some kind. The eyes of the demon seem to glare at you with a mocking evil light.", 	n=724, 	s=722, 	e="You blunder into a cold, hard wall.", 	w="You walk into something solid.", 	ne="You can\'t go that way.", 	nw="You can\'t go that way.", 	se="You can\'t go that way.", 	sw="You can\'t go that way.", 	i=724, 	o=722, 	u="You can\'t go that way.", 	d="You can\'t go that way."},
{room=724,  	title="Long hallway.", 	verbose="You are stood at the south end of a long, dark hallway, illuminated by dimly flickering candles in holders along the walls. There are stairs leading upwards from here, and a large, very solid looking oak door to your south.", 	n=725, 	s="The door is locked and looks very solid.", 	e="The candles flicker briefly as you bump into the wall.", 	w="The candles flicker briefly as you bump into the wall.", 	ne="The candles flicker briefly as you bump into the wall.", 	nw="The candles flicker briefly as you bump into the wall.", 	se="The candles flicker briefly as you bump into the wall.", 	sw="The candles flicker briefly as you bump into the wall.", 	i=725, 	o="The door is locked and looks very solid.", 	u=727, 	d="The floor is in the way."},
